import React, { Component } from "react";
import { Icon, Card, Tag, Timeline } from "antd";
import { connect } from "react-redux";
import Navigation from "../src/components/navigation";
import Marquee from "react-marquee-slider";
import styled from "styled-components";
import times from "lodash/times";

class Memes extends Component {
  render() {
    const { Meta } = Card;

    const Photo = styled.img`
      width: 300px;
      height: 387px;
      border-radius: 4px;
      box-shadow: 0 7px 20px 0 rgba(0, 0, 0, 0.12);
      object-fit: cover;
      object-position: top;
    `;

    const photos = [
      "../static/1percent.png",
      "../static/Boat.png",
      "../static/EstateMeme.png"
    ];

    return (
      <div>
        <div
          style={{
            height: "100vh",
            backgroundColor: this.props.batmode ? "black" : "white"
          }}
        >
          <Navigation />
          <div
            style={{
              display: "flex",
              justifyContent: "center",
              alignItems: "center",
              flexDirection: "row",
              height: "80vh",
              width: "100vw"
            }}
          >
            <div style={{ display: "column" }}>
              <div
                style={{
                  fontWeight: "bold",
                  fontSize: "4vw",
                  color: this.props.batmode ? "white" : "black",
                  textAlign: "center"
                }}
              >
                Gallery
              </div>

              <div>
                <Marquee velocity={25}>
                  {times(2, Number).map(id => {
                    return (
                      <Photo
                        src={photos[id]}
                        style={{
                          marginLeft: "80px"
                        }}
                      />
                    );
                  })}
                </Marquee>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }
}

const mapStateToProps = state => {
  const { batmode } = state.theme;
  return { batmode };
};

export default connect(mapStateToProps)(Memes);
